mapper.select:
select cfru.id as id, cfru.user_id as userId, su.name as username, cfru.create_time as createTime, sou.department_id as departmentId, sd.name as departmentName, sou.position as position from custom_form_role_user cfru join sys_user su on cfru.user_id = su.id left join sys_organization_user sou on su.id = sou.user_id and sou.organization_id = #{orgId} left join sys_department sd on sou.department_id = sd.id
cfru.role_id = #{request.customFormRoleId}
and su.name like concat('%', #{request.keyword}, '%')

choose.when:

order by


        cfru.id ${sortType}


        cfru.user_id ${sortType}


        su.name ${sortType}


        cfru.create_time ${sortType}


        sd.name ${sortType}


        sou.position ${sortType}


        cfru.create_time ${sortType}


, cfru.id asc
